arguments.command:
# Get available versions of the runtime
curl -sS "https://api.nuget.org/v3-flatcontainer/microsoft.netcore.app.runtime.android-arm64/index.json" 2>/dev/null | python3 -c "
import sys,json
versions=json.load(sys.stdin)['versions']
# Filter for stable .NET 9 and 10 versions
for v in versions:
    if v.startswith('9.0') or v.startswith('10.0'):
        if 'preview' not in v and 'rc' not in v:
            print(v)
" 2>/dev/null

